Page({
  data: {
    title: "Lab Page",
    description: "Use this page for spec, write, and validation experiments.",
    statusText: "Ready to call helloLab.",
    loading: false,
    inputValue: "codex-lab",
    selectedPreset: "codex-lab",
    callCount: 0,
    lastMessage: "",
    lastSuccess: null,
    history: [],
    result: null,
    presets: [
      {
        label: "default",
        value: "codex-lab",
        builtin: true
      },
      {
        label: "status-check",
        value: "status-check",
        builtin: true
      },
      {
        label: "hello-agent",
        value: "hello-agent",
        builtin: true
      }
    ],
    modules: [
      {
        name: "page routing",
        status: "ready"
      },
      {
        name: "cloud function skeleton",
        status: "ready"
      },
      {
        name: "feature sandbox",
        status: "open"
      }
    ]
  },

  async callHelloLab() {
    if (!wx.cloud) {
      this.setData({
        statusText: "wx.cloud is unavailable in the current runtime.",
        result: null
      });
      return;
    }

    this.setData({
      loading: true,
      statusText: "Calling helloLab...",
      result: null
    });

    try {
      const payload = {
        source: "lab-page",
        input: this.data.inputValue,
        requestedAt: new Date().toISOString()
      };
      const response = await wx.cloud.callFunction({
        name: "helloLab",
        data: payload
      });
      const result = response.result || null;
      const nextCount = this.data.callCount + 1;
      const historyItem = {
        input: payload.input || "",
        timestamp: result && result.data ? result.data.timestamp : payload.requestedAt
      };
      const dedupedHistory = this.data.history.filter((item) => item.input !== historyItem.input);
      const nextHistory = [historyItem].concat(dedupedHistory).slice(0, 5);

      this.setData({
        loading: false,
        statusText: "helloLab returned successfully.",
        callCount: nextCount,
        lastMessage: result && result.data ? result.data.message : "",
        lastSuccess: result && result.data ? {
          input: payload.input || "",
          message: result.data.message || "",
          timestamp: result.data.timestamp || payload.requestedAt
        } : null,
        history: nextHistory,
        result: result
      });
    } catch (error) {
      this.setData({
        loading: false,
        statusText: "helloLab call failed.",
        result: {
          code: 1,
          msg: error && error.errMsg ? error.errMsg : "unknown_error"
        }
      });
    }
  },

  clearResult() {
    this.setData({
      statusText: "Result cleared. Ready to call helloLab again.",
      lastMessage: "",
      result: null
    });
  },

  clearHistory() {
    this.setData({
      history: [],
      statusText: "History cleared. Ready for a fresh run."
    });
  },

  useLatestHistoryInput() {
    const latest = this.data.history[0];
    if (!latest || !latest.input) {
      this.setData({
        statusText: "No recent history input is available."
      });
      return;
    }

    this.setData({
      inputValue: latest.input,
      selectedPreset: "",
      statusText: "Latest history input restored."
    });
  },

  hasHistory() {
    return Array.isArray(this.data.history) && this.data.history.length > 0;
  },

  savePresetValue(value, successMessage) {
    const normalizedValue = (value || "").trim();
    if (!normalizedValue) {
      this.setData({
        statusText: "Type something before saving a preset."
      });
      return;
    }

    const existingPreset = this.data.presets.find((item) => item.value === normalizedValue);
    if (existingPreset) {
      this.setData({
        selectedPreset: existingPreset.value,
        statusText: "That preset already exists."
      });
      return;
    }

    const label = normalizedValue.length > 14 ? `${normalizedValue.slice(0, 14)}...` : normalizedValue;
    const customPresets = this.data.presets.filter((item) => !item.builtin);
    const trimmedCustomPresets = customPresets.slice(0, 2);
    const wasTruncated = customPresets.length > trimmedCustomPresets.length;
    const builtinPresets = this.data.presets.filter((item) => item.builtin);
    const nextPresets = builtinPresets.concat(trimmedCustomPresets, [
      {
        label,
        value: normalizedValue,
        builtin: false
      }
    ]);

    this.setData({
      presets: nextPresets,
      inputValue: normalizedValue,
      selectedPreset: normalizedValue,
      statusText: wasTruncated
        ? `${successMessage} Oldest custom preset was replaced.`
        : successMessage
    });
  },

  saveCurrentAsPreset() {
    const value = this.data.inputValue || "";
    this.savePresetValue(value, "Custom preset saved.");
  },

  saveSummaryAsPreset() {
    const lastSuccess = this.data.lastSuccess;
    if (!lastSuccess || !lastSuccess.input) {
      this.setData({
        statusText: "No successful input is available to save as a preset."
      });
      return;
    }

    const existingPreset = this.data.presets.find(
      (item) => item.value === lastSuccess.input
    );
    if (existingPreset) {
      this.setData({
        inputValue: lastSuccess.input,
        selectedPreset: lastSuccess.input,
        statusText: "Summary input applied from an existing preset."
      });
      return;
    }

    this.savePresetValue(
      lastSuccess.input,
      "Summary input saved as a custom preset."
    );
  },

  renameSelectedPreset() {
    const selectedValue = this.data.selectedPreset || "";
    const nextValue = (this.data.inputValue || "").trim();
    const selectedPreset = this.data.presets.find((item) => item.value === selectedValue);

    if (!selectedPreset || selectedPreset.builtin) {
      this.setData({
        statusText: "Select a custom preset before renaming it."
      });
      return;
    }

    if (!nextValue) {
      this.setData({
        statusText: "Type something before renaming the selected preset."
      });
      return;
    }

    const duplicatePreset = this.data.presets.find((item) => item.value === nextValue);
    if (duplicatePreset && duplicatePreset.value !== selectedValue) {
      this.setData({
        statusText: "Another preset already uses that value."
      });
      return;
    }

    const label = nextValue.length > 14 ? `${nextValue.slice(0, 14)}...` : nextValue;
    const nextPresets = this.data.presets.map((item) => {
      if (item.value !== selectedValue) {
        return item;
      }

      return {
        label,
        value: nextValue,
        builtin: false
      };
    });

    this.setData({
      presets: nextPresets,
      inputValue: nextValue,
      selectedPreset: nextValue,
      statusText: "Custom preset renamed."
    });
  },

  fillPreset(event) {
    const value = event.currentTarget.dataset.value || "";
    this.setData({
      inputValue: value,
      selectedPreset: value,
      statusText: "Preset applied. Ready to call helloLab."
    });
  },

  refillFromHistory(event) {
    const value = event.currentTarget.dataset.value || "";
    this.setData({
      inputValue: value,
      selectedPreset: "",
      statusText: "History item restored to the input box."
    });
  },

  rerunHistory(event) {
    const value = event.currentTarget.dataset.value || "";
    this.setData({
      inputValue: value,
      selectedPreset: "",
      statusText: "History item selected. Calling helloLab again..."
    });
    this.callHelloLab();
  },

  useLastSuccessInput() {
    const lastSuccess = this.data.lastSuccess;
    if (!lastSuccess || !lastSuccess.input) {
      this.setData({
        statusText: "No successful input is available to reuse."
      });
      return;
    }

    this.setData({
      inputValue: lastSuccess.input,
      selectedPreset: "",
      statusText: "Last successful input restored to the input box."
    });
  },

  clearLastSuccess() {
    if (!this.data.lastSuccess) {
      this.setData({
        statusText: "No successful summary to clear."
      });
      return;
    }

    this.setData({
      lastSuccess: null,
      statusText: "Last successful summary cleared."
    });
  },

  removePreset(event) {
    const value = event.currentTarget.dataset.value || "";
    const nextPresets = this.data.presets.filter((item) => item.value !== value);
    const remainingSelected = this.data.selectedPreset === value ? "" : this.data.selectedPreset;
    const fallbackPreset = nextPresets.find((item) => item.value === "codex-lab");
    const shouldFallback = !remainingSelected && fallbackPreset;
    this.setData({
      presets: nextPresets,
      selectedPreset: shouldFallback ? fallbackPreset.value : remainingSelected,
      inputValue: shouldFallback ? fallbackPreset.value : this.data.inputValue,
      statusText: shouldFallback
        ? "Custom preset removed. Default preset restored."
        : "Custom preset removed."
    });
  },

  restoreDefaultPreset() {
    this.setData({
      inputValue: "codex-lab",
      selectedPreset: "codex-lab",
      statusText: "Default preset restored."
    });
  },

  handleInputChange(event) {
    this.setData({
      inputValue: event.detail.value,
      selectedPreset: ""
    });
  }
});








<view class="page">
  <view class="hero">
    <text class="title">{{title}}</text>
    <text class="description">{{description}}</text>
  </view>

  <view class="stack">
    <block wx:for="{{modules}}" wx:key="name">
      <view class="module">
        <text class="module-name">{{item.name}}</text>
        <text class="module-status">{{item.status}}</text>
      </view>
    </block>
  </view>

  <view class="action-card">
    <text class="action-title">Cloud Function Check</text>
    <text class="action-desc">{{statusText}}</text>
    <text class="meta-line">call count: {{callCount}}</text>
    <text wx:if="{{lastMessage}}" class="meta-line">last message: {{lastMessage}}</text>
    <view class="preset-row">
      <block wx:for="{{presets}}" wx:key="label">
        <view class="preset-chip {{selectedPreset === item.value ? 'preset-chip-active' : ''}}">
          <button
            class="preset-button {{selectedPreset === item.value ? 'preset-button-active' : ''}}"
            data-value="{{item.value}}"
            bindtap="fillPreset"
            disabled="{{loading}}"
          >
            {{item.label}}
          </button>
          <button
            wx:if="{{!item.builtin}}"
            class="preset-remove"
            data-value="{{item.value}}"
            bindtap="removePreset"
            disabled="{{loading}}"
          >
            x
          </button>
        </view>
      </block>
    </view>
    <input
      class="input"
      type="text"
      value="{{inputValue}}"
      placeholder="Type something to echo"
      bindinput="handleInputChange"
    />
    <button class="action-button" bindtap="callHelloLab" loading="{{loading}}">
      Call helloLab
    </button>
    <button class="ghost-button" bindtap="saveCurrentAsPreset" disabled="{{loading}}">
      Save as preset
    </button>
    <button class="ghost-button" bindtap="renameSelectedPreset" disabled="{{loading}}">
      Rename selected preset
    </button>
    <button class="ghost-button" bindtap="restoreDefaultPreset" disabled="{{loading}}">
      Restore default preset
    </button>
    <button class="ghost-button" bindtap="clearResult" disabled="{{loading}}">
      Clear result
    </button>
  </view>

  <view wx:if="{{lastSuccess}}" class="summary-card">
    <text class="result-title">Last successful run</text>
    <text class="result-line">input: {{lastSuccess.input}}</text>
    <text class="result-line">message: {{lastSuccess.message}}</text>
    <text class="result-line">timestamp: {{lastSuccess.timestamp}}</text>
    <button class="ghost-button summary-button" bindtap="useLastSuccessInput" disabled="{{loading}}">
      Use summary input
    </button>
    <button class="ghost-button summary-button" bindtap="saveSummaryAsPreset" disabled="{{loading}}">
      Save summary as preset
    </button>
    <button class="ghost-button summary-button" bindtap="clearLastSuccess" disabled="{{loading}}">
      Clear summary
    </button>
  </view>

  <view wx:if="{{result}}" class="result-card">
    <text class="result-title">Result</text>
    <text class="result-line">code: {{result.code}}</text>
    <text class="result-line">msg: {{result.msg}}</text>
    <text wx:if="{{result.data}}" class="result-line">message: {{result.data.message}}</text>
    <text wx:if="{{result.data && result.data.echo}}" class="result-line">input: {{result.data.echo.input}}</text>
    <text wx:if="{{result.data && result.data.echo}}" class="result-line">source: {{result.data.echo.source}}</text>
    <text wx:if="{{result.data}}" class="result-line">timestamp: {{result.data.timestamp}}</text>
  </view>

  <view wx:if="{{history.length}}" class="history-card">
    <text class="result-title">Recent inputs</text>
    <button class="ghost-button history-button" bindtap="clearHistory" disabled="{{loading}}">
      Clear history
    </button>
    <button class="ghost-button history-button" bindtap="useLatestHistoryInput" disabled="{{loading || !history.length}}">
      Use latest input
    </button>
    <block wx:for="{{history}}" wx:key="timestamp">
      <view class="history-row">
        <view class="history-main" data-value="{{item.input}}" bindtap="refillFromHistory">
          <text class="history-input">{{item.input}}</text>
          <text class="history-time">{{item.timestamp}}</text>
        </view>
        <button
          class="history-run-button"
          data-value="{{item.input}}"
          bindtap="rerunHistory"
          disabled="{{loading}}"
        >
          Run again
        </button>
      </view>
    </block>
  </view>
  <view wx:else class="history-card history-empty">
    <text class="result-title">Recent inputs</text>
    <text class="result-line">Run helloLab once to populate history.</text>
  </view>
</view>
